script:
function setNum(sel, value) {
  var el = root_element.querySelector(sel + ' .num');
  if (el) el.textContent = value;
}

frappe.db.count('active_taq').then(function(count){
  setNum('#stat-voaz', count);
  setNum('#stat-completed', count);
});

frappe.db.count('mak_taq').then(function(count){
  setNum('#stat-makatib', count);
});

root_element.querySelector('#stat-voaz').style.cursor = 'pointer';
root_element.querySelector('#stat-voaz').addEventListener('click', function(){
  frappe.set_route('list', 'active_taq');
});

root_element.querySelector('#stat-makatib').style.cursor = 'pointer';
root_element.querySelector('#stat-makatib').addEventListener('click', function(){
  frappe.set_route('list', 'mak_taq');
});

root_element.querySelector('#stat-completed').style.cursor = 'pointer';
root_element.querySelector('#stat-completed').addEventListener('click', function(){
  frappe.set_route('list', 'active_taq');
});

root_element.querySelector('#link-voaz').addEventListener('click', function(e){
  e.preventDefault();
  frappe.set_route('list', 'active_taq');
});

root_element.querySelector('#link-makatib').addEventListener('click', function(e){
  e.preventDefault();
