});

root_element.querySelector('#link-anawin').addEventListener('click', function(e){
  e.preventDefault();
  frappe.set_route('list', 'enac_taq');
});

// جلب اسم المستخدم المسجّل دخوله وعرض جملة الترحيب
function updateGreeting() {
  var fullname = frappe.session.user_fullname || frappe.session.user;
  var greetingEl = root_element.querySelector('#greeting-text');
  if (greetingEl) {
    greetingEl.textContent = 'مرحباً بك، ' + fullname;
  }
}
updateGreeting();

// عرض الوقت والتاريخ الحالي وتحديثه كل ثانية
function updateDateTime() {
  var el = root_element.querySelector('#datetime-text');
  if (!el) return;
  var now = new Date();
  var options = {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit'
  };
  el.textContent = now.toLocaleString('ar-SA-u-ca-gregory', options);
}
updateDateTime();
var __clockInterval = setInterval(updateDateTime, 1000);

