style:
@import url('https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800;900&display=swap');

.root_element {
  width: 100%;
}
.block {
  width: 100%;
}
.page-body, .workspace-sidebar-toggle ~ .page-container .container,
.page-container .container,
.layout-main-section-wrapper,
.codex-editor,
.codex-editor__redactor,
.ce-block,
.ce-block__content,
.ce-toolbar__content {
  max-width: 100% !important;
}

/* ============================================================
   الهوية البصرية الجديدة: الأزرق الداكن والذهبي الفاخر
   ============================================================ */
.block, .block * {
  box-sizing: border-box;
  font-family: 'Tajawal', sans-serif;
}

.block {
  position: relative;
  /* التدرج اللوني النفطي الفاخر المستوحى من الهيدر */
  background: radial-gradient(120% 160% at 100% 0%, rgba(34, 163, 204, .16) 0%, transparent 45%),
              linear-gradient(120deg, #05141D 0%, #1A2E3B 52%, #0D5F85 100%) !important;
  border: 1px solid rgba(34, 163, 204, .22);
  border-radius: 20px;
  padding: 46px 50px;
  overflow: hidden;
  color: #FFFFFF;
  box-shadow: 0 10px 26px -6px rgba(5, 20, 29, .3) !important;
  transition: all .3s cubic-bezier(.22, 1, .36, 1);
}

.block:hover {
  box-shadow: 0 24px 48px -14px rgba(5, 20, 29, .45) !important;
  transform: translateY(-2px);
}

/* نمط الشبكة الهندسية المحدث */
.pattern {
  position: absolute; 
  inset: 0;
  background-image:
    repeating-linear-gradient(45deg, rgba(34, 163, 204, .05) 0, rgba(34, 163, 204, .05) 1px, transparent 1px, transparent 30px),
    repeating-linear-gradient(-45deg, rgba(34, 163, 204, .05) 0, rgba(34, 163, 204, .05) 1px, transparent 1px, transparent 30px);
  pointer-events: none;
  opacity: 0.8;
}

/* الحلقات الجمالية بلون ذهبي دافئ ناعم */
.gold-ring {
  position: absolute; 
  left: -60px; 
  top: -60px;
  width: 220px; 
  height: 220px;
  border: 1.5px solid rgba(197, 168, 128, .25);
  border-radius: 50%;
  transition: transform .8s cubic-bezier(.22, 1, .36, 1);
  pointer-events: none;
}
.block:hover .gold-ring { transform: rotate(35deg) scale(1.05); }

.gold-ring.small {
  left: -20px; 
  top: 30px;
  width: 120px; 
  height: 120px;
  border-color: rgba(197, 168, 128, .15);
}
.block:hover .gold-ring.small { transform: rotate(-35deg) scale(0.95); }

/* الترويسة العلوية */
.topbar {
  position: relative;
  z-index: 2;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 20px;
  margin-bottom: 24px;
  flex-wrap: wrap;
}
.topbar-left {
  display: flex;
  align-items: center;
}
.topbar-left .logo {
  height: 52px;
  width: auto;
  object-fit: contain;
  filter: drop-shadow(0 4px 12px rgba(0,0,0,.35));
}
.topbar-right {
  text-align: left;
  direction: rtl;
}
.topbar-right .greeting {
  font-size: 16px;
  font-weight: 700;
  color: #FFFFFF;
}
.topbar-right .greeting::before {
  content: '👋 ';
}
.topbar-right .datetime {
  font-size: 13px;
  color: #cbd5e1;
  margin-top: 4px;
  opacity: .9;
}

/* المحتوى الأساسي */
.content {
  position: relative; 
  z-index: 2;
  display: flex; 
  align-items: center; 
  justify-content: space-between;
  gap: 30px; 
  flex-wrap: wrap;
}
.eyebrow {
  display: inline-flex; 
  align-items: center; 
  gap: 8px;
  font-size: 13px; 
  font-weight: 700;
  color: #c5a880; /* لون ذهبي وقور */
  border: 1px solid rgba(197, 168, 128, .3);
  background: rgba(197, 168, 128, .05);
  padding: 6px 14px; 
  border-radius: 30px;
  margin-bottom: 16px;
  transition: all .2s ease;
}
.eyebrow:hover { 
  background: rgba(197, 168, 128, 0.15); 
  border-color: rgba(197, 168, 128, .5);
}
.eyebrow::before { content: '◆'; font-size: 9px; }

.block h1 { 
  font-size: 30px; 
  font-weight: 900; 
  line-height: 1.4; 
  margin-bottom: 8px; 
  color: #FFFFFF; 
}
.block h1 span { 
  color: #c5a880; /* تمييز ذهبي */
}
.block p.sub { 
  font-size: 14.5px; 
  color: #cbd5e1; 
  max-width: 520px; 
  line-height: 1.9; 
  opacity: .95; 
  margin: 0; 
}

/* بطاقات الإحصائيات الفخمة */
.stats { 
  display: flex; 
  gap: 14px; 
}
.stat {
  background: rgba(255, 255, 255, .04);
  border: 1px solid rgba(197, 168, 128, .2);
  border-radius: 14px;
  padding: 18px 24px;
  text-align: center;
  min-width: 115px;
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  transition: all .2s cubic-bezier(.22, 1, .36, 1);
}
.stat:hover {
  transform: translateY(-4px);
  background: rgba(197, 168, 128, 0.08);
  border-color: rgba(197, 168, 128, .5);
  box-shadow: 0 10px 20px -5px rgba(197, 168, 128, 0.15);
}
.stat .num { 
  font-size: 26px; 
  font-weight: 900; 
  color: #FFFFFF; 
}
.stat .lbl { 
  font-size: 12px; 
  color: #cbd5e1; 
  margin-top: 4px; 
}

/* الفاصل الزخرفي */
.divider {
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(197, 168, 128, .4), transparent);
  margin: 30px 0 0;
}

/* الروابط السفلية */
.links { 
  display: flex; 
  gap: 28px; 
  margin-top: 22px; 
  flex-wrap: wrap; 
}
.links a {
  color: #cbd5e1; 
  text-decoration: none; 
  font-size: 14px; 
  font-weight: 700;
  display: inline-flex; 
  align-items: center; 
  gap: 8px;
  opacity: .9;
  transition: all .2s ease;
}
.links a:hover { 
  opacity: 1; 
  color: #c5a880; 
}
.links a::after { 
  content: '←'; 
  font-size: 13px; 
  color: #c5a880; 
  transition: transform .2s ease; 
}
.links a:hover::after { 
  transform: translateX(-4px); 
}

/* الزر الرئيسي المذهب الفاخر */
.gold-btn-platform {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  background: linear-gradient(135deg, #c5a880 0%, #a88d63 100%) !important;
  color: #05141D !important; /* لون داكن جداً ليكون النص مقروءاً بوضوح */
  font-weight: 800;
  font-size: 14.5px;
  padding: 12px 26px;
  border-radius: 30px;
  margin-top: 20px;
  text-decoration: none;
  box-shadow: 0 6px 20px rgba(197, 168, 128, 0.25);
  transition: all 0.3s cubic-bezier(.22, 1, .36, 1);
  border: 1px solid rgba(255, 255, 255, 0.15);
}

.gold-btn-platform:hover {
  background: linear-gradient(135deg, #e5c9a3 0%, #c5a880 100%) !important;
  transform: translateY(-3px);
  box-shadow: 0 8px 25px rgba(197, 168, 128, 0.45);
}

.gold-btn-platform .icon-arrow {
  font-style: normal;
  font-weight: 900;
  transition: transform 0.3s ease;
}
.gold-btn-platform:hover .icon-arrow {
  transform: translateX(-5px);
}

/* تجاوب التصميم مع الشاشات الصغيرة */
@media (max-width: 768px) {
  .gold-btn-platform {
    display: flex;
    justify-content: center;
    width: 100%;
  }
}

script:
//========================================
//      AWQAF PREMIUM HERO
//========================================

const greetingElement = root_element.querySelector("#hero-greeting");
const userElement = root_element.querySelector("#user-name");
const timeElement = root_element.querySelector("#hero-time");
const dateElement = root_element.querySelector("#hero-date");

//========================================
// اسم المستخدم
//========================================

let fullName = "";

if (frappe.session && frappe.session.user_fullname) {
    fullName = frappe.session.user_fullname;
} else if (frappe.boot && frappe.boot.user && frappe.boot.user.full_name) {
    fullName = frappe.boot.user.full_name;
} else if (frappe.session && frappe.session.user) {
    fullName = frappe.session.user;
}

userElement.textContent = fullName || "المستخدم";

//========================================
// الأشهر والأيام
//========================================

const months = [
    "يناير",
    "فبراير",
    "مارس",
    "أبريل",
    "مايو",
    "يونيو",
    "يوليو",
    "أغسطس",
    "سبتمبر",
    "أكتوبر",
    "نوفمبر",
    "ديسمبر"
];

const days = [
    "الأحد",
    "الإثنين",
    "الثلاثاء",
    "الأربعاء",
    "الخميس",
    "الجمعة",
    "السبت"
];

//========================================
// تحديث الوقت
//========================================

function updateClock() {

    const now = new Date();

    let hour = now.getHours();
    let minute = String(now.getMinutes()).padStart(2, "0");
    let second = String(now.getSeconds()).padStart(2, "0");

    let displayHour = String(hour).padStart(2, "0");

    timeElement.textContent =
        `${displayHour}:${minute}:${second}`;

    dateElement.innerHTML =
        `${days[now.getDay()]}<br>${now.getDate()} ${months[now.getMonth()]} ${now.getFullYear()}`;

    //------------------------------------
    // الترحيب حسب الوقت
    //------------------------------------

    let greeting = "";

    if (hour >= 5 && hour < 12) {

        greeting = "🌅 صباح الخير";

    }

    else if (hour >= 12 && hour < 17) {

        greeting = "☀️ طاب يومكم";

    }

    else if (hour >= 17 && hour < 21) {

        greeting = "🌇 مساء الخير";

    }

    else {

        greeting = "🌙 أسعد الله مساءكم";

    }

    greetingElement.textContent = greeting;

}

updateClock();

setInterval(updateClock, 1000);

//========================================
// تأثير بسيط عند تحريك الماوس
//========================================

const hero = root_element.querySelector(".awqaf-premium");

hero.addEventListener("mousemove", function(e) {

    const rect = hero.getBoundingClientRect();

    const x = e.clientX - rect.left;

    const y = e.clientY - rect.top;

    hero.style.backgroundPosition =
        `${50 + (x - rect.width / 2) / 40}% ${50 + (y - rect.height / 2) / 40}%`;

});

hero.addEventListener("mouseleave", function() {

    hero.style.backgroundPosition = "center";

});

