/* ============================================================
   الهوية البصرية: سماوي ERP
   ============================================================ */
.tq-theme-oceanic {
  /* 1) الأسطح والخلفيات */
  --tq-bg:            #e0f2fe;
  --tq-surface:       #ffffff;
  --tq-surface-alt:   #f1f5f9;
  --tq-border:        #cbd5e1;
  --tq-border-soft:   #f1f5f9;

  /* 2) حبر النصوص */
  --tq-ink:           #05141D;
  --tq-ink-soft:      #1A2E3B;
  --tq-ink-faint:     #64748b;

  /* 3) الألوان الأساسية والثانوية */
  --tq-accent:        #0D5F85;
  --tq-accent-dark:   #1A2E3B;
  --tq-accent-light:  #157CA7;
  --tq-accent-soft:   #e0f2fe;
  --tq-accent-ring:   rgba(13, 95, 133, .15);

  --tq-gold:          #22A3CC;
  --tq-gold-light:    #5bc0de;
  --tq-gold-soft:     #e0f7fa;
  --tq-gold-ring:     rgba(34, 163, 204, .16);

  /* 4) تدرجات الهيدر */
  --tq-hero-1:        #05141D;
  --tq-hero-2:        #1A2E3B;
  --tq-hero-3:        #0D5F85;
  --tq-cream-soft:    #cbd5e1;

  /* 5) المقاييس الهندسية */
  --tq-radius-sm: 10px;
  --tq-radius-md: 14px;
  --tq-radius-lg: 20px;
  --tq-radius-xl: 26px;

  --tq-space-1: 6px;
  --tq-space-2: 10px;
  --tq-space-3: 16px;
  --tq-space-4: 24px;
  --tq-space-5: 36px;

  /* 6) الظلال */
  --tq-shadow-xs: 0 1px 2px rgba(5, 20, 29, .05);
  --tq-shadow-sm: 0 2px 8px rgba(5, 20, 29, .06);
  --tq-shadow-md: 0 10px 26px -6px rgba(5, 20, 29, .14);
  --tq-shadow-lg: 0 24px 48px -14px rgba(5, 20, 29, .22);

  /* 7) الحركة والخطوط */
  --tq-ease: cubic-bezier(.22, 1, .36, 1);
  --tq-ease-soft: cubic-bezier(.4, 0, .2, 1);
  --tq-font: "Tajawal", "Segoe UI", "Cairo", Arial, sans-serif;

  display: block;
  font-family: var(--tq-font);
  color: var(--tq-ink);
  direction: rtl;
  text-align: right;
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
}

.tq-theme-oceanic *,
.tq-theme-oceanic *::before,
.tq-theme-oceanic *::after {
  box-sizing: border-box;
}

@media (prefers-reduced-motion: reduce) {
  .tq-theme-oceanic * { transition: none !important; animation: none !important; }
}

.tq-theme-oceanic .hd-dashboard-wrapper {
    margin-bottom: var(--tq-space-4);
}

/* ============================================================
   بطاقة الترحيب (Hero) بأسلوب الهيدر الرئيسي الداكن
   ============================================================ */
.tq-theme-oceanic .hd-welcome-card-premium {
    background:
        radial-gradient(120% 160% at 100% 0%, rgba(34, 163, 204, .16) 0%, transparent 45%),
        linear-gradient(120deg, var(--tq-hero-1) 0%, var(--tq-hero-2) 52%, var(--tq-hero-3) 100%);
    color: #ffffff;
    border-radius: var(--tq-radius-xl);
    padding: var(--tq-space-5);
    display: flex;
    justify-content: space-between;
    align-items: center;
    position: relative;
    isolation: isolate;
    overflow: hidden;
    box-shadow: var(--tq-shadow-lg);
    margin-bottom: var(--tq-space-4);
    border: 1px solid rgba(34, 163, 204, .22);
}

/* نمط زخرفي مدمج (نفس نمط الهيدر الأساسي في الهوية) */
.tq-theme-oceanic .hd-welcome-card-premium::before {
    content: '';
    position: absolute;
    inset: 0;
    z-index: 0;
    pointer-events: none;
    opacity: .4;
    background-image:
        repeating-linear-gradient(45deg, rgba(34, 163, 204, .07) 0, rgba(34, 163, 204, .07) 1px, transparent 1px, transparent 30px),
        repeating-linear-gradient(-45deg, rgba(34, 163, 204, .07) 0, rgba(34, 163, 204, .07) 1px, transparent 1px, transparent 30px);
    -webkit-mask-image: linear-gradient(to left, black, transparent 75%);
            mask-image: linear-gradient(to left, black, transparent 75%);
}

.tq-theme-oceanic .hd-welcome-card-premium::after {
    content: "";
    position: absolute;
    width: 260px;
    height: 260px;
    left: -80px;
    top: -90px;
    border: 1.5px solid rgba(34, 163, 204, .28);
    border-radius: 50%;
    pointer-events: none;
    z-index: 0;
}

.tq-theme-oceanic .hd-card-content {
    max-width: 75%;
    position: relative;
    z-index: 1;
}

.tq-theme-oceanic .hd-badge-premium {
    background: rgba(34, 163, 204, .1);
    color: var(--tq-gold-light);
    border: 1px solid rgba(34, 163, 204, 0.38);
    padding: 6px 14px;
    border-radius: 30px;
    font-size: 12px;
    font-weight: 700;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    margin-bottom: var(--tq-space-3);
    letter-spacing: .2px;
}

.tq-theme-oceanic .pulse-dot {
    width: 8px;
    height: 8px;
    background-color: var(--tq-gold);
    border-radius: 50%;
    display: inline-block;
    box-shadow: 0 0 0 0 rgba(34, 163, 204, 0.7);
    animation: oceanic-pulse 2s infinite;
}

@keyframes oceanic-pulse {
    0% { transform: scale(0.95); box-shadow: 0 0 0 0 rgba(34, 163, 204, 0.7); }
    70% { transform: scale(1); box-shadow: 0 0 0 6px rgba(34, 163, 204, 0); }
    100% { transform: scale(0.95); box-shadow: 0 0 0 0 rgba(34, 163, 204, 0); }
}

.tq-theme-oceanic .hd-welcome-card-premium h1 {
    color: #ffffff !important;
    font-size: 26px;
    font-weight: 900;
    margin: 0 0 var(--tq-space-2) 0 !important;
    letter-spacing: -.2px;
    text-shadow: 0 2px 4px rgba(5, 20, 29, 0.3);
}

.tq-theme-oceanic .hd-welcome-card-premium p {
    color: var(--tq-cream-soft);
    font-size: 14px;
    line-height: 1.9;
    margin: 0 0 var(--tq-space-4) 0;
    opacity: .92;
}

.tq-theme-oceanic .hd-action-container {
    display: flex;
    flex-direction: column;
    gap: 12px;
    max-width: 420px;
}

.tq-theme-oceanic .hd-btn-main {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    padding: 14px 24px;
    background: linear-gradient(90deg, var(--tq-accent) 0%, var(--tq-accent-light) 100%);
    color: #ffffff !important;
    border-radius: var(--tq-radius-sm);
    font-size: 14px;
    font-weight: 700;
    text-decoration: none !important;
    box-shadow: 0 4px 14px var(--tq-accent-ring);
    transition: all 0.2s var(--tq-ease);
    border: 1px solid rgba(255, 255, 255, 0.1);
}

.tq-theme-oceanic .hd-btn-main:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(13, 95, 133, 0.4);
    background: linear-gradient(90deg, var(--tq-accent-light) 0%, var(--tq-accent) 100%);
}

.tq-theme-oceanic .hd-sub-buttons {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
}

.tq-theme-oceanic .hd-btn-sub {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    padding: 10px 16px;
    border-radius: 8px;
    font-size: 12px;
    font-weight: 600;
    text-decoration: none !important;
    transition: all 0.2s ease;
}

.tq-theme-oceanic .sub-primary {
    background-color: rgba(255, 255, 255, 0.07);
    color: #f1f5f9 !important;
    border: 1px solid rgba(255, 255, 255, 0.1);
}

.tq-theme-oceanic .sub-primary:hover {
    background-color: rgba(255, 255, 255, 0.15);
    color: #ffffff !important;
    transform: translateY(-1px);
}

.tq-theme-oceanic .sub-secondary {
    background-color: transparent;
    color: var(--tq-cream-soft) !important;
    border: 1px solid rgba(203, 213, 225, 0.2);
}

.tq-theme-oceanic .sub-secondary:hover {
    border-color: rgba(203, 213, 225, 0.5);
    color: #ffffff !important;
    background-color: rgba(255, 255, 255, 0.02);
}

.tq-theme-oceanic .hd-card-icon-premium {
    position: relative;
    z-index: 1;
}

.tq-theme-oceanic .hd-card-icon-premium svg {
    width: 110px;
    height: 110px;
    color: rgba(34, 163, 204, 0.15);
    transform: rotate(15deg);
}

/* ============================================================
   شبكة بطاقات الوصول السريع (بنفس أسلوب الكروت في الهوية)
   ============================================================ */
.tq-theme-oceanic .hd-stats-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
    gap: var(--tq-space-3);
}

.tq-theme-oceanic .hd-stat-card {
    background: var(--tq-surface);
    border: 1px solid var(--tq-border-soft);
    border-radius: var(--tq-radius-lg);
    padding: var(--tq-space-4);
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    transition: transform .2s var(--tq-ease), box-shadow .2s var(--tq-ease), border-color .2s var(--tq-ease);
    position: relative;
    overflow: hidden;
    box-shadow: var(--tq-shadow-xs);
}

/* دائرة زخرفية شفافة في زاوية الكرت (نفس أسلوب tq-stat-card) */
.tq-theme-oceanic .hd-stat-card::after {
    content: "";
    position: absolute;
    inset-inline-end: -30px;
    top: -30px;
    width: 100px;
    height: 100px;
    border-radius: 50%;
    background: var(--tq-card-accent, var(--tq-accent));
    opacity: .07;
    transition: opacity .2s var(--tq-ease), transform .3s var(--tq-ease);
    pointer-events: none;
}

.tq-theme-oceanic .hd-stat-card:hover {
    transform: translateY(-4px);
    border-color: color-mix(in srgb, var(--tq-card-accent, var(--tq-accent)) 30%, var(--tq-border));
    box-shadow: var(--tq-shadow-md);
}

.tq-theme-oceanic .hd-stat-card:hover::after {
    opacity: .12;
    transform: scale(1.15);
}

.tq-theme-oceanic .hd-stat-header {
    position: relative;
    z-index: 1;
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
}

.tq-theme-oceanic .hd-stat-title {
    font-size: 15px;
    font-weight: 800;
    color: var(--tq-ink);
}

.tq-theme-oceanic .hd-stat-icon {
    font-size: 18px;
    width: 38px;
    height: 38px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 12px;
    transition: background 0.2s ease, color 0.2s ease;
}

.tq-theme-oceanic .hd-stat-desc {
    position: relative;
    z-index: 1;
    font-size: 12.5px;
    color: var(--tq-ink-soft);
    margin-bottom: 20px;
    line-height: 1.6;
}

.tq-theme-oceanic .hd-stat-link {
    position: relative;
    z-index: 1;
    font-size: 12.5px;
    font-weight: 700;
    text-decoration: none !important;
    transition: padding 0.2s ease;
    align-self: flex-start;
}

.tq-theme-oceanic .hd-stat-card:hover .hd-stat-link {
    padding-right: 6px;
}

/* ربط ألوان الكروت بمتغير --tq-card-accent الموحّد في الهوية */
.tq-theme-oceanic .card-blue   { --tq-card-accent: var(--tq-accent);       border-top: 4px solid var(--tq-accent); }
.tq-theme-oceanic .card-blue   .hd-stat-link { color: var(--tq-accent); }
.tq-theme-oceanic .card-blue   .hd-stat-icon { background: var(--tq-accent-soft); }

.tq-theme-oceanic .card-purple { --tq-card-accent: var(--tq-accent-light); border-top: 4px solid var(--tq-accent-light); }
.tq-theme-oceanic .card-purple .hd-stat-link { color: var(--tq-accent-light); }
.tq-theme-oceanic .card-purple .hd-stat-icon { background: var(--tq-accent-soft); }

.tq-theme-oceanic .card-green  { --tq-card-accent: var(--tq-gold);        border-top: 4px solid var(--tq-gold); }
.tq-theme-oceanic .card-green  .hd-stat-link { color: var(--tq-gold); }
